<template>
  <div>

    <!-- TITULO -->
    <h2 class="titulo">Lista de Productos</h2>

    <!-- BUSCADOR -->
    <div class="buscador">
      <input 
        type="text"
        v-model="busqueda"
        placeholder="Buscar producto..."
      />
    </div>

    <!-- CATEGORIAS -->
    <div class="categorias">
      <button @click="categoriaSeleccionada='todas'">Todos</button>
      <button @click="categoriaSeleccionada='tecnologia'">Tecnología</button>
      <button @click="categoriaSeleccionada='telefonia'">Telefonía</button>
      <button @click="categoriaSeleccionada='audio'">Audio</button>
      <button @click="categoriaSeleccionada='gaming'">Gaming</button>
    </div>

    <!-- PRODUCTOS -->
    <div class="contenedor">

      <div 
        class="producto"
        v-for="producto in productosFiltrados"
        :key="producto.id"
      >

        <img :src="producto.image" />

        <h3>{{ producto.title }}</h3>

        <p>{{ producto.description }}</p>

        <p class="precio">
          $ {{ producto.price.toLocaleString('es-CL') }}
        </p>

        <p class="categoria">
          Categoría: {{ producto.category }}
        </p>

      </div>

    </div>

  </div>
</template>

<script>
export default {

  data() {
    return {

      busqueda: "",

      categoriaSeleccionada: "todas",

      productos: [

        {
          id:1,
          title:"Notebook Lenovo",
          price:550000,
          image:"https://via.placeholder.com/200",
          description:"Notebook ideal para estudio y trabajo",
          category:"tecnologia"
        },

        {
          id:2,
          title:"Smartphone Samsung",
          price:320000,
          image:"https://via.placeholder.com/200",
          description:"Teléfono con excelente cámara",
          category:"telefonia"
        },

        {
          id:3,
          title:"Audífonos Bluetooth",
          price:45000,
          image:"https://via.placeholder.com/200",
          description:"Audífonos inalámbricos de alta calidad",
          category:"audio"
        },

        {
          id:4,
          title:"Mouse Gamer RGB",
          price:25000,
          image:"https://via.placeholder.com/200",
          description:"Mouse gamer con iluminación RGB",
          category:"gaming"
        },

        {
          id:5,
          title:"Teclado Mecánico",
          price:65000,
          image:"https://via.placeholder.com/200",
          description:"Teclado mecánico para gaming",
          category:"gaming"
        },

        {
          id:6,
          title:"Tablet Samsung",
          price:280000,
          image:"https://via.placeholder.com/200",
          description:"Tablet ideal para estudio y entretenimiento",
          category:"tecnologia"
        }

      ]
    }
  },

  computed: {

    productosFiltrados(){

      let resultado = this.productos

      if(this.categoriaSeleccionada !== "todas"){
        resultado = resultado.filter(
          p => p.category === this.categoriaSeleccionada
        )
      }

      if(this.busqueda !== ""){
        resultado = resultado.filter(
          p => p.title.toLowerCase().includes(this.busqueda.toLowerCase())
        )
      }

      return resultado
    }

  }

}
</script>

<style scoped>

.titulo{
  text-align:center;
  color:navy;
  font-size:30px;
  margin-top:20px;
}

/* BUSCADOR */

.buscador{
  text-align:center;
  margin:20px;
}

.buscador input{
  padding:10px;
  width:250px;
  border-radius:5px;
  border:1px solid #ccc;
}

/* CATEGORIAS */

.categorias{
  text-align:center;
  margin-bottom:20px;
}

.categorias button{
  margin:5px;
  padding:8px 15px;
  background-color:#0d6efd;
  color:white;
  border:none;
  border-radius:5px;
  cursor:pointer;
}

.categorias button:hover{
  background-color:#084298;
}

/* PRODUCTOS */

.contenedor{
  display:grid;
  grid-template-columns:repeat(3,1fr);
  gap:20px;
  padding:20px;
}

.producto{
  border:1px solid #ddd;
  border-radius:10px;
  padding:15px;
  text-align:center;
  box-shadow:0 2px 5px rgba(0,0,0,0.1);
}

.producto img{
  width:150px;
  margin-bottom:10px;
}

.precio{
  color:green;
  font-weight:bold;
  font-size:18px;
}

.categoria{
  font-size:12px;
  color:gray;
}

</style>